// NQxb_Artifact_Update_v1__Normalize_Request
// v2: Add tags support (add/remove semantics at spine level)
// UPDATE-ONLY: Require artifact_id, reject if missing

const raw = $json ?? {};

const body =
  raw.body && typeof raw.body === "object" && !Array.isArray(raw.body)
    ? raw.body
    : null;

const req = body ?? raw;

const asObj = (v) =>
  v && typeof v === "object" && !Array.isArray(v) ? v : {};

const artifact_id = req.artifact_id ?? null;
const artifact_type = (req.artifact_type ?? "").trim();

// UPDATE_ONLY: artifact_id is REQUIRED
if (!artifact_id || artifact_id.trim() === '') {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "UPDATE_ONLY",
          message: "artifact.update is update-only. Use artifact.create for new artifacts.",
          details: {
            hint: "artifact_id field is required for UPDATE operations."
          },
        },
      },
    },
  ];
}

// Parse tags (top-level, NOT inside extension)
// Only set tags if there are actual operations to perform
const rawTags = req.tags ?? null;
let tags = null;
if (rawTags && typeof rawTags === "object" && !Array.isArray(rawTags)) {
  const add = Array.isArray(rawTags.add)
    ? rawTags.add.filter(t => typeof t === "string" && t.trim() !== "").map(t => t.trim())
    : [];
  const remove = Array.isArray(rawTags.remove)
    ? rawTags.remove.filter(t => typeof t === "string" && t.trim() !== "").map(t => t.trim())
    : [];
  if (add.length > 0 || remove.length > 0) {
    tags = { add, remove };
  }
}

const canonical = {
  gw_action: req.gw_action ?? "artifact.update",
  gw_workspace_id: req.gw_workspace_id ?? null,
  artifact_type: artifact_type,
  artifact_id: artifact_id.trim(),

  // Extension fields (type-specific, validated downstream)
  extension: asObj(req.extension),

  // Tags (spine-level, add/remove semantics) — v2
  tags: tags,

  // deleted_at (BLOCKED - UNDECIDED per Mutability Registry)
  deleted_at: req.deleted_at ?? null,
};

canonical._gw_debug = {
  received_shape: body ? "body" : "flat",
  operation: "UPDATE",
  has_tags: tags !== null,
};

return [{ json: canonical }];

// NQxb_Artifact_Update_v1__Validate_Request
// v3.0: Tags support — either extension OR tags required (not both mandatory)
// UPDATE-only validation (strict, predictable, preserves payload)

const req = $json ?? {};
const errors = [];

function isNonEmptyString(v) {
  return typeof v === "string" && v.trim().length > 0;
}

function asObj(v) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : {};
}

// Required: gw_workspace_id
if (!isNonEmptyString(req.gw_workspace_id)) {
  errors.push({ field: "gw_workspace_id", reason: "required", expected: "uuid string" });
}

// Required: artifact_type
if (!isNonEmptyString(req.artifact_type)) {
  errors.push({ field: "artifact_type", reason: "required", expected: "non-empty string" });
}

// Required: artifact_id
if (!isNonEmptyString(req.artifact_id)) {
  errors.push({ field: "artifact_id", reason: "required", expected: "uuid string" });
}

// v3: Either extension (with fields) OR tags must be provided
const ext = asObj(req.extension);
const hasExtension = Object.keys(ext).length > 0;
const hasTags = req.tags !== null && req.tags !== undefined;

if (!hasExtension && !hasTags) {
  errors.push({
    field: "extension_or_tags",
    reason: "required",
    expected: "At least one of: extension (object with fields) or tags (object with add/remove arrays)"
  });
}

// Validate tags structure if provided
if (hasTags) {
  const tags = req.tags;
  if (typeof tags !== "object" || Array.isArray(tags)) {
    errors.push({ field: "tags", reason: "invalid_type", expected: "object with add and/or remove arrays" });
  } else {
    if (tags.add !== undefined && !Array.isArray(tags.add)) {
      errors.push({ field: "tags.add", reason: "invalid_type", expected: "array of strings" });
    }
    if (tags.remove !== undefined && !Array.isArray(tags.remove)) {
      errors.push({ field: "tags.remove", reason: "invalid_type", expected: "array of strings" });
    }
    if (Array.isArray(tags.add)) {
      const bad = tags.add.filter(t => typeof t !== "string");
      if (bad.length > 0) {
        errors.push({ field: "tags.add", reason: "invalid_values", expected: "all elements must be strings" });
      }
    }
    if (Array.isArray(tags.remove)) {
      const bad = tags.remove.filter(t => typeof t !== "string");
      if (bad.length > 0) {
        errors.push({ field: "tags.remove", reason: "invalid_values", expected: "all elements must be strings" });
      }
    }
  }
}

if (errors.length > 0) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "VALIDATION_ERROR",
          message: "Validation failed for artifact.update (UPDATE)",
          details: {
            validation_errors: errors,
            operation: "UPDATE",
            artifact_type: req.artifact_type ?? null,
            artifact_id: req.artifact_id ?? null,
          },
        },
        gw_action: req.gw_action ?? "artifact.update",
        gw_workspace_id: req.gw_workspace_id ?? null,
        artifact_type: req.artifact_type ?? null,
        artifact_id: req.artifact_id ?? null,
        _gw_debug: req._gw_debug ?? undefined,
      },
    },
  ];
}

// Pass-through with normalized fields
return [
  {
    json: {
      ...req,
      ok: true,
      _gw_route: "ok",
      gw_action: req.gw_action ?? "artifact.update",
      extension: ext,
      tags: req.tags ?? null,
      deleted_at: req.deleted_at ?? null,
      _gw_debug: {
        ...(req._gw_debug ?? {}),
        operation: "UPDATE",
        received_shape: (req._gw_debug && req._gw_debug.received_shape) ? req._gw_debug.received_shape : "flat",
      },
    },
  },
];

// Type Registry Guard
// Check artifact type against qxb_artifact_type_registry
// Error code: ARTIFACT_TYPE_NOT_ALLOWED
// Fail-closed: no row or disabled = reject

// Get original request from the Guard_Error_ShortCircuit node (ok path)
const originalRequest = $node['NQxb_Artifact_Update_v1__Guard_Error_ShortCircuit'].json;

// Get registry lookup result (may be empty if no row found)
const registryRow = $json;

const artifact_type = originalRequest.artifact_type;

// FAIL-CLOSED: No row found = type not registered
if (!registryRow || !registryRow.artifact_type) {
  return [{
    json: {
      ok: false,
      _gw_route: 'error',
      gw_action: originalRequest.gw_action ?? 'artifact.update',
      gw_workspace_id: originalRequest.gw_workspace_id ?? null,
      artifact_type: artifact_type,
      artifact_id: originalRequest.artifact_id ?? null,
      error: {
        code: 'ARTIFACT_TYPE_NOT_ALLOWED',
        message: `Artifact type '${artifact_type}' is not allowed`,
        details: {
          artifact_type: artifact_type,
          reason: 'not_registered',
          hint: 'Type must be registered in qxb_artifact_type_registry'
        }
      },
      timestamp: new Date().toISOString()
    }
  }];
}

// Type found but disabled
if (registryRow.enabled === false) {
  return [{
    json: {
      ok: false,
      _gw_route: 'error',
      gw_action: originalRequest.gw_action ?? 'artifact.update',
      gw_workspace_id: originalRequest.gw_workspace_id ?? null,
      artifact_type: artifact_type,
      artifact_id: originalRequest.artifact_id ?? null,
      error: {
        code: 'ARTIFACT_TYPE_NOT_ALLOWED',
        message: `Artifact type '${artifact_type}' is not allowed`,
        details: {
          artifact_type: artifact_type,
          reason: 'disabled',
          registry_enabled: false,
          hint: 'Type is registered but currently disabled'
        }
      },
      timestamp: new Date().toISOString()
    }
  }];
}

// Type is registered and enabled - pass through original request
return [{ json: originalRequest }];

// NQxb_Artifact_Update_v1__Check_Mutability_Rules
// v2: Mutability Registry v2 — Universal spine-level tag updates
//
// Tags are organizational metadata, not extension content.
// Tags can be updated on ALL artifact types (including snapshot, restart).
// Extension immutability rules remain unchanged.
//
// Decision matrix:
//   tags_only on any type          → ALLOW (bypass extension check)
//   tags + extension on immutable  → BLOCK (extension immutable, tags not applied)
//   tags + extension on journal    → BLOCK (journal undecided, tags not applied)
//   tags + extension on project    → ALLOW (validate extension per allowlist)
//   extension_only on project      → ALLOW (existing v1 behavior)

const existing = $json;
const normalizeNode = $node['NQxb_Artifact_Update_v1__Normalize_Request'].json;

// Check if artifact was found
if (!existing || !existing.artifact_id) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "NOT_FOUND",
          message: "Artifact not found for UPDATE operation",
          details: {
            artifact_id: normalizeNode.artifact_id,
            workspace_id: normalizeNode.gw_workspace_id,
            operation: "UPDATE",
          },
        },
      },
    },
  ];
}

const artifact_type = existing.artifact_type?.trim();

// Detect what's being updated
const hasTags = normalizeNode.tags !== null && normalizeNode.tags !== undefined;
const extension = normalizeNode.extension || {};
const extensionFields = Object.keys(extension);
const hasExtension = extensionFields.length > 0;
const tagsOnly = hasTags && !hasExtension;

// RULE: deleted_at is UNDECIDED_BLOCKED
if (normalizeNode.deleted_at !== null && normalizeNode.deleted_at !== undefined) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "MUTABILITY_ERROR",
          message: "Field 'deleted_at' is UNDECIDED_BLOCKED and cannot be updated.",
          details: {
            field: "deleted_at",
            artifact_type: artifact_type,
            artifact_id: existing.artifact_id,
            registry_rule: "UNDECIDED_BLOCKED",
            source: "Mutability Registry v2",
          },
        },
      },
    },
  ];
}

// RULE: snapshot and restart — extension immutable, tags allowed
if (artifact_type === "snapshot" || artifact_type === "restart") {
  if (hasExtension) {
    return [
      {
        json: {
          ok: false,
          _gw_route: "error",
          error: {
            code: "IMMUTABILITY_ERROR",
            message: `Artifact type '${artifact_type}' is immutable. Extension fields cannot be updated. Only tag updates are allowed.`,
            details: {
              artifact_type: artifact_type,
              artifact_id: existing.artifact_id,
              operation_attempted: "UPDATE",
              registry_rule: "CREATE_ONLY (extension), UPDATE_ALLOWED (tags)",
              source: "Mutability Registry v2",
              hint: hasTags ? "Remove extension fields from your request. Tags can be updated separately." : undefined,
            },
          },
        },
      },
    ];
  }
  // tags_only on snapshot/restart → ALLOW (fall through to success)
}

// RULE: journal — extension undecided, tags allowed
if (artifact_type === "journal") {
  if (hasExtension) {
    return [
      {
        json: {
          ok: false,
          _gw_route: "error",
          error: {
            code: "JOURNAL_MUTABILITY_UNDECIDED",
            message: "Journal extension update policy is not locked. Only tag updates are allowed.",
            details: {
              artifact_type: "journal",
              artifact_id: existing.artifact_id,
              operation_attempted: "UPDATE",
              registry_rule: "UNDECIDED_BLOCKED (extension), UPDATE_ALLOWED (tags)",
              source: "Mutability Registry v2",
              doctrine: "Journal INSERT-ONLY (Temporary)",
              hint: hasTags
                ? "Remove extension fields. Tags can be updated separately."
                : "Use artifact.create to append new journal entries.",
            },
          },
        },
      },
    ];
  }
  // tags_only on journal → ALLOW (fall through to success)
}

// RULE: For project artifacts, validate extension fields against allowlist
if (artifact_type === "project" && hasExtension) {
  const allowedFields = ["operational_state", "state_reason"];
  const disallowedFields = extensionFields.filter((f) => !allowedFields.includes(f));

  if (disallowedFields.length > 0) {
    if (disallowedFields.includes("lifecycle_stage")) {
      return [
        {
          json: {
            ok: false,
            _gw_route: "error",
            error: {
              code: "MUTABILITY_ERROR",
              message: "Field 'lifecycle_stage' is PROMOTE_ONLY and cannot be updated via artifact.update.",
              details: {
                field: "extension.lifecycle_stage",
                artifact_type: "project",
                artifact_id: existing.artifact_id,
                registry_rule: "PROMOTE_ONLY",
                source: "Mutability Registry v2",
                hint: "Use artifact.promote operation to change lifecycle_stage.",
              },
            },
          },
        },
      ];
    }

    return [
      {
        json: {
          ok: false,
          _gw_route: "error",
          error: {
            code: "MUTABILITY_ERROR",
            message: `Disallowed fields in extension for project UPDATE: ${disallowedFields.join(", ")}`,
            details: {
              disallowed_fields: disallowedFields,
              allowed_fields: allowedFields,
              artifact_type: "project",
              artifact_id: existing.artifact_id,
              source: "Mutability Registry v2",
            },
          },
        },
      },
    ];
  }
}

// Ensure at least something is being updated
if (!hasTags && !hasExtension) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "VALIDATION_ERROR",
          message: "No updateable fields provided. Provide tags and/or extension fields.",
          details: {
            artifact_type: artifact_type,
            artifact_id: existing.artifact_id,
          },
        },
      },
    },
  ];
}

// Mutability checks passed
return [
  {
    json: {
      ok: true,
      _gw_route: "ok",
      gw_action: normalizeNode.gw_action ?? "artifact.update",
      gw_workspace_id: normalizeNode.gw_workspace_id ?? null,

      artifact_id: existing.artifact_id,
      workspace_id: existing.workspace_id,
      artifact_type: existing.artifact_type,

      _has_tags: hasTags,
      _has_extension: hasExtension,
      _tags_only: tagsOnly,

      _normalized_request: normalizeNode,
      _existing_artifact: existing,

      _gw_debug: {
        ...(normalizeNode._gw_debug ?? {}),
        mutability: "passed",
        operation: "UPDATE",
        has_tags: hasTags,
        has_extension: hasExtension,
        tags_only: tagsOnly,
        source: "Mutability Registry v2",
      },
    },
  },
];

// NQxb_Artifact_Update_v1__Apply_Tag_Operations
// Compute new tags array from existing tags + add/remove operations
// v1: Idempotent add/remove semantics, de-duplicated
//
// Reads from: Check_Mutability_Rules (_existing_artifact.tags)
// Reads from: Normalize_Request (requested tag operations)

const mutability = $node['NQxb_Artifact_Update_v1__Check_Mutability_Rules'].json;
const normalizeNode = $node['NQxb_Artifact_Update_v1__Normalize_Request'].json;

const hasTags = mutability._has_tags;
const hasExtension = mutability._has_extension;

if (!hasTags) {
  // No tag operations requested — pass through
  return [{
    json: {
      _has_tags: false,
      _has_extension: hasExtension,
      _new_tags: null,
      _tags_body: null,
    }
  }];
}

// Get existing tags from spine (may be null or array)
const existingTags = mutability._existing_artifact?.tags ?? [];
const currentTags = Array.isArray(existingTags) ? existingTags : [];

// Get requested operations
const tagOps = normalizeNode.tags || {};
const toAdd = Array.isArray(tagOps.add)
  ? tagOps.add.filter(t => typeof t === "string" && t.trim().length > 0).map(t => t.trim())
  : [];
const toRemove = Array.isArray(tagOps.remove)
  ? tagOps.remove.filter(t => typeof t === "string" && t.trim().length > 0).map(t => t.trim())
  : [];

// Apply: remove specified tags, then add new tags, de-duplicate
const removeSet = new Set(toRemove);
let newTags = currentTags.filter(t => !removeSet.has(t));
const existingSet = new Set(newTags);
for (const tag of toAdd) {
  if (!existingSet.has(tag)) {
    newTags.push(tag);
    existingSet.add(tag);
  }
}

return [{
  json: {
    _has_tags: true,
    _has_extension: hasExtension,
    _new_tags: newTags,
    _tags_body: JSON.stringify({ tags: newTags }),
    _tags_debug: {
      existing: currentTags,
      added: toAdd,
      removed: toRemove,
      result: newTags,
    }
  }
}];

// NQxb_Artifact_Update_v1__Prepare_Project_Extension_Update
// v2: Use $node references instead of $json for stability
// Extract allowed fields (operational_state, state_reason) for project UPDATE

const normalizeNode = $node['NQxb_Artifact_Update_v1__Normalize_Request'].json;
const mutabilityNode = $node['NQxb_Artifact_Update_v1__Check_Mutability_Rules'].json;
const extension = normalizeNode.extension || {};

// Only update fields that are explicitly provided
const hasOperationalState = 'operational_state' in extension;
const hasStateReason = 'state_reason' in extension;

const updateFields = {
  artifact_id: mutabilityNode.artifact_id,
};

if (hasOperationalState) {
  updateFields.operational_state = extension.operational_state;
}

if (hasStateReason) {
  updateFields.state_reason = extension.state_reason;
}

updateFields._has_operational_state = hasOperationalState;
updateFields._has_state_reason = hasStateReason;

return [{ json: updateFields }];

// NQxb_Artifact_Update_v1__Prepare_Query_Call
// Get artifact_id from the flow for final query

const normalizeNode = $node['NQxb_Artifact_Update_v1__Normalize_Request'].json;
const mutabilityNode = $node['NQxb_Artifact_Update_v1__Check_Mutability_Rules'].json;

const artifact_id = mutabilityNode.artifact_id || normalizeNode.artifact_id;

return [
  {
    json: {
      saved_artifact_id: artifact_id,
      saved_workspace_id: normalizeNode.gw_workspace_id,
      saved_artifact_type: mutabilityNode.artifact_type || normalizeNode.artifact_type,
    },
  },
];

// NQxb_Artifact_Update_v1__Build_Query_Request
// Build a *correct* artifact.query request after UPDATE, even if the DB Update node outputs {}.
//
// Key idea: NEVER trust $json here because Supabase Update often returns an empty item.
// Instead, pull canonical IDs from the Normalize node (or other stable upstream nodes).

const normalize = $node["NQxb_Artifact_Update_v1__Normalize_Request"]?.json ?? {};
const validate   = $node["NQxb_Artifact_Update_v1__Validate_Request"]?.json ?? {};

const gw_workspace_id = normalize.gw_workspace_id ?? validate.gw_workspace_id ?? null;
const artifact_type   = normalize.artifact_type   ?? validate.artifact_type   ?? null;
const artifact_id     = normalize.artifact_id     ?? validate.artifact_id     ?? null;

return [
  {
    json: {
      gw_action: "artifact.query",
      gw_workspace_id,
      artifact_type,
      artifact_id,
      selector: {
        hydrate: true,
      },
      _gw_debug: {
        routed_from: "NQxb_Artifact_Update_v1",
        next: "artifact.query (hydrate)",
        source_ids: {
          gw_workspace_id,
          artifact_type,
          artifact_id,
        },
      },
    },
  },
];

// NQxb_Artifact_Update_v1__Return_Update_Ack
// v2: Include tags in response
// KGB TERMINAL — UPDATE ONLY
// Never trust Supabase UPDATE output.
// Always return a stable acknowledgement.

const normalize = $node["NQxb_Artifact_Update_v1__Normalize_Request"].json;
const tagOps = $node["NQxb_Artifact_Update_v1__Apply_Tag_Operations"]?.json ?? {};

const updatedFields = Object.keys(normalize.extension || {}).filter(k => k.length > 0);
if (tagOps._has_tags) {
  updatedFields.push("tags");
}

return [
  {
    json: {
      ok: true,
      gw_action: "artifact.update",
      operation: "UPDATE",
      artifact_id: normalize.artifact_id,
      artifact_type: normalize.artifact_type,
      gw_workspace_id: normalize.gw_workspace_id,
      updated_fields: updatedFields,
      tags_updated: tagOps._has_tags ?? false,
      _kgb: {
        status: "UPDATE_CONFIRMED",
        note: "Update completed.",
        version: "STAGED-v11-tags-update-2026-02-08",
      },
    },
  },
];

// NQxb_Artifact_Update_v1__Return_Error_Passthrough
// Terminal node: pass-through the incoming payload unchanged.
// Use for any error path to guarantee the workflow returns a real JSON envelope
// instead of dead-ending into "".

return $input.all();
